import{c as e,Q as o,j as r,m as a}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"致初入人世的年轻人","description":"","frontmatter":{"title":"致初入人世的年轻人","date":"2026-05-24T00:00:00.000Z","source":"co-created","seed":"一位长者对出入社会的年轻人的忠告","style":"let","to":"all","tags":["忠告","virtù","机运","入世"]},"headers":[],"relativePath":"seeds/elder-counsel/index.md","filePath":"seeds/elder-counsel/index.md"}'),p={name:"seeds/elder-counsel/index.md"};function l(n,t,s,i,u,c){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="致初入人世的年轻人" tabindex="-1">致初入人世的年轻人 <a class="header-anchor" href="#致初入人世的年轻人" aria-label="Permalink to &quot;致初入人世的年轻人&quot;">​</a></h1><blockquote><p>佛罗伦萨，1520 年</p><p>你正站在门槛上。身后是你所熟悉的秩序——书本、课堂、对错分明的世界。身前是一切都模糊的地方，没人告诉你正确答案，甚至没人承认有正确答案。</p><p>让我告诉你一些我在门槛这边学到的事。</p></blockquote><h2 id="一、世界不会按照它应该的方式运转" tabindex="-1">一、世界不会按照它应该的方式运转 <a class="header-anchor" href="#一、世界不会按照它应该的方式运转" aria-label="Permalink to &quot;一、世界不会按照它应该的方式运转&quot;">​</a></h2><p>你在学校里学到的是：做对的事，就有好的结果。</p><p>这是你能学到的最危险的谎言。</p><p>我不是说做对的事没有价值——而是说，做对的事和得到好的结果之间，没有必然的因果关系。你会在职场上看到：最诚实的人未必最受信任，最努力的人未必最先晋升，最有道理的人未必赢得辩论。</p><p>这不是因为世界是邪恶的。这是因为世界是<strong>复杂的</strong>。</p><p>《君主论》第 15 章有一段你们大概没读过的话：</p><blockquote><p>&quot;许多事物看起来是德能（virtù），可是如果照办了就会自取灭亡，而另一些事情看起来是恶行（vizio），可是如果照办了却会给他带来安全与福祉。&quot;</p></blockquote><p>这不是在教你作恶。这是在教你<strong>看清</strong>。一个看不清世界如何运转的人，无论多么善良，都会被碾碎——不是被恶人碾碎，而是被现实碾碎。</p><p><strong>忠告一：不要把道德判断和事实判断混为一谈。先看清世界如何运转，再决定你要如何在其中行事。</strong></p><h2 id="二、你只有一半的牌" tabindex="-1">二、你只有一半的牌 <a class="header-anchor" href="#二、你只有一半的牌" aria-label="Permalink to &quot;二、你只有一半的牌&quot;">​</a></h2><p>第 25 章是我被引用最多、误解也最多的段落：</p><blockquote><p>&quot;命运是我们半个行动的主宰，但留下其余一半——或几乎一半——由我们支配。&quot;</p></blockquote><p>你们把它当成一句励志格言：&quot;只要努力就能成功！&quot;不。我说的是：<strong>你最多只能控制一半</strong>。剩下的一半是机运——时代、出身、偶然事件、其他人的选择。</p><p>这意味着什么？</p><p><strong>不要为不属于你的那一半自责。</strong> 当事情不顺利时，不要自动归因于&quot;我还不够好&quot;。也许你只是碰上了洪水——而堤坝还没修好。</p><p><strong>不要浪费属于你的那一半。</strong> 你能控制的那一半，不要用来抱怨不公、等待救援或者幻想好运。用那半局来修堤坝——积累技能、建立联盟、储备资源。</p><blockquote><p>&quot;当命运变化时，如果一个人是谨慎的，他就会被毁灭；但如果他是果敢的，他就能成功。&quot;</p></blockquote><p><strong>忠告二：接受控制力的上限，但把可控的部分用到极致。</strong></p><h2 id="三、区分朋友和盟友" tabindex="-1">三、区分朋友和盟友 <a class="header-anchor" href="#三、区分朋友和盟友" aria-label="Permalink to &quot;三、区分朋友和盟友&quot;">​</a></h2><p>你会遇到很多人。其中一些对你好，一些对你坏，大多数对你无所谓。</p><p>你需要区分三类人：</p><p><strong>朋友</strong>——关心你本身的人。他们很少，可能一只手数得过来。保护他们。</p><p><strong>盟友</strong>——和你有共同利益的人。他们很多，但联盟会随利益变化而瓦解。不要把盟友当朋友，也不要因为盟友离开而愤怒——那就像因为河流改道而愤怒一样无意义。</p><p><strong>其余</strong>——对你无所谓的人。他们是大多数。不要试图讨好所有人，那是浪费你那一半牌的方式。</p><p><strong>忠告三：把感情留给朋友，把计算留给盟友，把礼貌留给其余。不要搞反。</strong></p><h2 id="四、让人害怕好过让人爱" tabindex="-1">四、让人害怕好过让人爱 <a class="header-anchor" href="#四、让人害怕好过让人爱" aria-label="Permalink to &quot;四、让人害怕好过让人爱&quot;">​</a></h2><p>这可能是你最不想听的建议。但我不是说你要当暴君。</p><p>我说的是：<strong>在&quot;被喜欢&quot;和&quot;被尊重&quot;之间，永远选择后者。</strong></p><p>被喜欢的人很多——好说话的人、从不拒绝的人、从不冒犯任何人的人。但当你需要他们时，他们不会为你站在前面。因为喜欢是一种情绪，情绪会变。</p><p>被尊重的人不一样。尊重来自能力、底线和一致性——你知道这个人能做到什么、不能容忍什么、会在关键时刻如何行动。尊重是可预测的，而可预测是一种力量。</p><blockquote><p>&quot;对人们，要么加以抚慰，要么加以消灭；因为人们会报复微小的伤害，但对重大的伤害却无能为力。&quot;</p></blockquote><p>这话听起来残酷，但它的实际含义是：<strong>不要制造无意义的敌意，但一旦有必要冲突，就要让对方没有反击的能力</strong>。小摩擦会变成大仇；彻底的胜利反而终结了敌意。</p><p><strong>忠告四：与其被喜欢但被忽视，不如被尊重甚至被忌惮。</strong></p><h2 id="五、在风平浪静时修堤坝" tabindex="-1">五、在风平浪静时修堤坝 <a class="header-anchor" href="#五、在风平浪静时修堤坝" aria-label="Permalink to &quot;五、在风平浪静时修堤坝&quot;">​</a></h2><p>最后一条，也是最重要的。</p><p>我在第 25 章中打过一个比方：命运像一个暴虐的河流——</p><blockquote><p>&quot;当它发怒时，淹没平原，推倒树木和房屋……但尽管它如此凶猛，人们在风平浪静时仍然可以修筑堤坝和渠道，以便下次洪水来临时，水可以流入运河，不至于如此泛滥成灾。&quot;</p></blockquote><p>你刚入社会，很可能还在风平浪静期——有工作、有收入、有计划。这时候修堤坝看起来毫无必要。</p><p>但洪水一定会来。可能是裁员，可能是行业剧变，可能是健康危机，可能是任何你现在想象不到的事。当它来的时候，你唯一能依靠的就是在风平浪静时修的东西：技能、储蓄、人脉、心理韧性。</p><p><strong>忠告五：顺境不是用来享受的，是用来备荒的。</strong></p><hr><blockquote><p>这不是一个善良的世界，但也不是一个邪恶的世界。它只是一个<strong>真实</strong>的世界——效用的真实（verità effettuale），而非想象的真实。</p><p>祝你好运。你那一半牌，记得打好。</p><p>——尼可洛</p></blockquote><hr><p><em>相关原文：<a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/en/XV-chapter.md" target="_blank" rel="noreferrer">《君主论》第 15 章</a> · <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/en/XXV-chapter.md" target="_blank" rel="noreferrer">《君主论》第 25 章</a> · <a href="https://niflhum.top/machiavelli-library/library/machiavelli/discourses/" target="_blank" rel="noreferrer">《论李维》</a></em></p>',46)])])}const q=e(p,[["render",l]]);export{d as __pageData,q as default};
